        issues.append(f"C12='{c12}' should be Elena Vasquez")

    # D12: FMLA
    d12 = str(get_cell_value(ws, "D12") or "").strip().lower()
    if "fmla" not in d12:
        issues.append(f"D12='{d12}' should be FMLA")

    # E12: April 20, 2026
