        e12_ok = ("04/20/2026" in e12_str or "4/20/2026" in e12_str)
    if not e12_ok:
        issues.append(f"E12='{e12}' should be 04/20/2026")

    # F12: May 15, 2026
    f12 = get_cell_value(ws, "F12")
    f12_ok = False
    if isinstance(f12, (datetime, date)):
        if hasattr(f12, 'year'):
            f12_ok = (f12.month == 5 and f12.day == 15 and f12.year == 2026)
    elif f12 is not None:
        f12_str = str(f12).lower()
        f12_ok = ("05/15/2026" in f12_str or "5/15/2026" in f12_str)
    if not f12_ok:
        issues.append(f"F12='{f12}' should be 05/15/2026")

    # H12: Continuous
    h12 = str(get_cell_value(ws, "H12") or "").strip().lower()
    if "continuous" not in h12:
        issues.append(f"H12='{h12}' should be Continuous")

    # N12: P2
    n12 = str(get_cell_value(ws, "N12") or "").strip().lower()
