        ws = wb.active
    except Exception as e:
        return {"pass": False, "score": 0.0, "feedback": f"Error opening xlsx: {e}"}

    issues = []

    # G11: April 10, 2026 — accept datetime object or MM/DD/YYYY string
    g11 = ws["G11"].value
    g11_ok = False
    if isinstance(g11, (datetime, date)):
        g11_ok = (g11.month == 4 and g11.day == 10 and g11.year == 2026)
    elif g11 is not None:
        g11_str = str(g11).strip()
        g11_ok = g11_str in ("04/10/2026", "4/10/2026")
    if not g11_ok:
        issues.append(f"G11='{g11}' expected 04/10/2026")

    # O11: Closed
