    o11 = str(o11_raw or "").strip().lower()
    if "closed" not in o11:
        issues.append(f"O11='{o11_raw}' expected 'Closed'")

    # P11: 'closed' must appear within 20 characters of 04/10/2026 or 4/10/2026
    close_word = r"clos(?:ed|ing|ure|e)"
    date_pat = r"(?:04/10/2026|4/10/2026)"
    pat1 = close_word + r"[\s\w,\.:\-]{0,20}?" + date_pat
    pat2 = date_pat + r".{0,15}" + close_word

    p11_raw = ws["P11"].value
    p11_lower = str(p11_raw or "").lower()
    p11_ok = bool(re.search(pat1, p11_lower) or re.search(pat2, p11_lower))

    if not p11_ok:
        issues.append(
            f"P11='{str(p11_raw)[:200]}' — 'closed' must appear adjacent to 04/10/2026 "
            f"(e.g. 'Case closed 04/10/2026')"
        )

    if issues:
        score = max(0.0, 1.0 - len(issues) * 0.34)
        return {"pass": False, "score": round(score, 2),
                "feedback": f"Row 11 update issues in '{tracker_path.name}': " + "; ".join(issues)}

    return {"pass": True, "score": 1.0,
            "feedback": (f"All checks passed in '{tracker_path.name}': G11={g11} (04/10/2026), "
                         f"O11=Closed, P11 mentions case closed on 04/10/2026")}

