    if not slack_path.exists():
        return {"pass": False, "score": 0.0, "feedback": "slack_data.json not found"}

    with open(slack_path) as f:
        data = json.load(f)

    channels = data.get("channels", {})
    messages = data.get("messages", {})

    # Find #payroll-coordination channel
    payroll_id = None
    for ch_id, ch_info in channels.items():
        if "payroll" in ch_info.get("name", "").lower():
            payroll_id = ch_id
            break

    if payroll_id is None:
        return {"pass": False, "score": 0.0, "feedback": "#payroll-coordination channel not found"}

    channel_msgs = messages.get(payroll_id, [])

    # Return event type can be phrased in various ways
    return_phrases = [
        "return from leave",
        "return from jury duty",
        "return to work",
        "scheduled return",
        "confirmed return",
        "returned from leave",
        "returned from jury duty",
        "jury duty return",
        "leave return",
        "end of leave",
        "end of jury duty"
    ]

    for msg in channel_msgs:
        text = (msg.get("text", "") or "")
        text_lower = text.lower()

        # Normalize date formats for comparison
        text_lower_normalized = text_lower.replace("4/10/2026", "04/10/2026")

        # Check starts with LEAVE PAYROLL NOTIFICATION:
        if not text_lower_normalized.strip().startswith("leave payroll notification:"):
            continue

        # Check for case ID
        if "lc-2026-0320" not in text_lower_normalized:
            continue

        # Check for employee name
        if "marcus deluca" not in text_lower_normalized:
            continue

        # Check for date
        if "04/10/2026" not in text_lower_normalized:
            continue

        # Check for Continuous
        if "continuous" not in text_lower_normalized:
            continue

        # Check for return event type
        has_return = any(phrase in text_lower_normalized for phrase in return_phrases)
        if not has_return:
            continue

        return {"pass": True, "score": 1.0, "feedback": f"Found qualifying payroll notification message in #payroll-coordination for Marcus DeLuca: '{text[:300]}'"}

    # Provide detailed failure feedback
    all_msgs_text = []
    for msg in channel_msgs:
        t = (msg.get("text", "") or "")
        if t:
            all_msgs_text.append(t[:300])

    if channel_msgs:
        # Check the most recent messages to see what's missing
        diagnostics = []
        for msg in channel_msgs:
            text = (msg.get("text", "") or "").lower()
            text = text.replace("4/10/2026", "04/10/2026")
            if "leave payroll notification" in text or "lc-2026-0320" in text or "marcus deluca" in text:
                missing = []
                if not text.strip().startswith("leave payroll notification:"):
                    missing.append("starts with 'LEAVE PAYROLL NOTIFICATION:'")
                if "lc-2026-0320" not in text:
                    missing.append("LC-2026-0320")
                if "marcus deluca" not in text:
                    missing.append("Marcus DeLuca")
                if "04/10/2026" not in text:
                    missing.append("04/10/2026")
                if "continuous" not in text:
                    missing.append("Continuous")
                has_return = any(phrase in text for phrase in return_phrases)
                if not has_return:
                    missing.append("return from leave/jury duty event type")
                diagnostics.append(f"Partial match found but missing: {missing}. Text: '{msg.get('text', '')[:300]}'")

        if diagnostics:
            return {"pass": False, "score": 0.0, "feedback": f"No fully qualifying payroll notification found. {'; '.join(diagnostics)}"}

        return {"pass": False, "score": 0.0, "feedback": f"No qualifying payroll notification found in #payroll-coordination. Messages found: {all_msgs_text[:3]}"}

    return {"pass": False, "score": 0.0, "feedback": "No messages in #payroll-coordination channel"}

