    except Exception as e:
        return {"pass": False, "score": 0.0, "feedback": f"Failed to open '{tracker_path.name}': {e}"}

    # Try named sheet first, fall back to active
    target_sheet = None
    for name in wb.sheetnames:
        if name.strip().lower() == "leave tracker":
            target_sheet = wb[name]
            break

    if target_sheet is None:
        target_sheet = wb.active

    row_12_values = []
    for cell in target_sheet[12]:
        if cell.value is not None and str(cell.value).strip() != "":
            row_12_values.append((cell.column_letter, cell.value))

    if len(row_12_values) == 0:
        return {"pass": False, "score": 0.0, "feedback": f"Row 12 in '{tracker_path.name}' is completely empty."}

    values_summary = ", ".join([f"{col}: {val}" for col, val in row_12_values[:10]])
    if len(row_12_values) > 10:
        values_summary += f" ... and {len(row_12_values) - 10} more"

    return {"pass": True, "score": 1.0, "feedback": f"Row 12 is not empty. Found {len(row_12_values)} non-empty cell(s): {values_summary}"}
